// templates/golden-signals.jsonnet
local panels = import '../lib/genai-panels.libsonnet';
local vars   = import '../lib/variables.libsonnet';
local g      = import 'github.com/grafana/grafonnet/gen/grafonnet-latest/main.libsonnet';

g.dashboard.new('GenAI — Golden Signals Overview')
+ g.dashboard.withUid('genai-golden-signals-v1')
+ g.dashboard.withRefresh('30s')
+ g.dashboard.withTimepicker(g.dashboard.timepicker.withRefreshIntervals(['10s','30s','1m','5m']))
+ g.dashboard.withVariables([vars.datasource, vars.env, vars.model, vars.region])
+ g.dashboard.withPanels(
    g.util.grid.wrapPanels([
      panels.latencyPanel        { gridPos+: { w: 12, h: 8 } },
      panels.tokenThroughput     { gridPos+: { w: 12, h: 8 } },
      panels.errorRateStat       { gridPos+: { w: 6,  h: 4 } },
      panels.errorRateTimeseries { gridPos+: { w: 18, h: 4 } },
      panels.costPerRequest      { gridPos+: { w: 6,  h: 4 } },
      panels.rateLimitTimeseries { gridPos+: { w: 12, h: 8 } },
      panels.queueDepthGauge     { gridPos+: { w: 12, h: 8 } },
    ], panelWidth=12, panelHeight=8)
  )

// Annotation: firing alerts overlay
local alertAnnotation =
  g.dashboard.annotation.withName('Firing Alerts')
  + g.dashboard.annotation.withDatasource('Alertmanager')
  + g.dashboard.annotation.withEnable(true)
  + g.dashboard.annotation.withHide(false)
  + g.dashboard.annotation.withIconColor('red');

// Annotation: deploy events from Loki
local deployAnnotation =
  g.dashboard.annotation.withName('Deploys')
  + g.dashboard.annotation.withDatasource('Loki')
  + g.dashboard.annotation.withExpr('{job="deploy-events"} | json | action="deploy"')
  + g.dashboard.annotation.withIconColor('blue');

// Monthly spend forecast (stat panel)
local forecastStat =
  g.panel.stat.new('Monthly Forecast')
  + g.panel.stat.queryOptions.withTargets([
      promQuery.new(
        '$datasource',
        // Linear extrapolation: MTD spend / days elapsed * days in month
        |||
          sum(increase(genai_cost_usd_total{env="$env"}[30d]))
          / scalar(day_of_month())
          * scalar(days_in_month())
        |||
      )
    ])
  + g.panel.stat.standardOptions.withUnit('currencyUSD')
  + g.panel.stat.standardOptions.thresholds.withSteps([
      { color: 'green', value: null },
      { color: 'yellow', value: 8000 },
      { color: 'red',    value: 12000 },
    ]);

// Error breakdown timeseries
local errorBreakdown =
  g.panel.timeSeries.new('Error Rate by Type')
  + g.panel.timeSeries.queryOptions.withTargets([
      promQuery.new('$datasource',
        'sum(rate(genai_request_errors_total{env="$env"}[5m])) by (error_type)'
      )
    ])
  + g.panel.timeSeries.fieldConfig.defaults.custom.withLineWidth(2)
  + g.panel.timeSeries.options.withLegend({ displayMode: 'table', placement: 'right' });

# Latency comparison — one series per model variant
histogram_quantile(0.95,
  sum by (model, le) (
    rate(genai_request_duration_seconds_bucket{
      env="$env", model=~"$model"
    }[5m])
  )
)

// teams/search/golden-signals.jsonnet
local base = import '../../templates/golden-signals.jsonnet';
local vars = import '../../lib/variables.libsonnet';
local g    = import 'github.com/grafana/grafonnet/gen/grafonnet-latest/main.libsonnet';

local featureVar =
  g.dashboard.variable.query.new('feature')
  + g.dashboard.variable.query.withDatasourceFromVariable(vars.datasource)
  + g.dashboard.variable.query.queryTypes.withLabelValues(
      'feature_name',
      'genai_requests_total{env="$env", team="search"}'
    );

base
+ g.dashboard.withVariables(base.variables + [featureVar])
+ g.dashboard.withTitle('Search Team — Golden Signals')
+ g.dashboard.withUid('genai-golden-search-v1')

// lib/genai-panels.libsonnet
local g           = import 'github.com/grafana/grafonnet/gen/grafonnet-latest/main.libsonnet';
local promQuery   = g.query.prometheus;

{
  latencyPanel:
    g.panel.timeSeries.new('Request Latency (P50 / P95 / P99)')
    + g.panel.timeSeries.queryOptions.withTargets([
        promQuery.new('$datasource',
          'histogram_quantile(0.50, sum by (le) (rate(genai_request_duration_seconds_bucket{env="$env",model=~"$model"}[5m])))'
        ) + promQuery.withLegendFormat('P50'),
        promQuery.new('$datasource',
          'histogram_quantile(0.95, sum by (le) (rate(genai_request_duration_seconds_bucket{env="$env",model=~"$model"}[5m])))'
        ) + promQuery.withLegendFormat('P95'),
        promQuery.new('$datasource',
          'histogram_quantile(0.99, sum by (le) (rate(genai_request_duration_seconds_bucket{env="$env",model=~"$model"}[5m])))'
        ) + promQuery.withLegendFormat('P99'),
      ])
    + g.panel.timeSeries.standardOptions.withUnit('s')
    + g.panel.timeSeries.options.withTooltipMode('multi'),

  tokenThroughput:
    g.panel.timeSeries.new('Token Throughput')
    + g.panel.timeSeries.queryOptions.withTargets([
        promQuery.new('$datasource',
          'sum(rate(genai_tokens_total{env="$env",model=~"$model"}[5m])) by (token_type)'
        ) + promQuery.withLegendFormat('{{token_type}}'),
      ])
    + g.panel.timeSeries.standardOptions.withUnit('tokens/s'),

  errorRateStat:
    g.panel.stat.new('Error Rate')
    + g.panel.stat.queryOptions.withTargets([
        promQuery.new('$datasource',
          'sum(rate(genai_request_errors_total{env="$env"}[5m])) / sum(rate(genai_requests_total{env="$env"}[5m]))'
        )
      ])
    + g.panel.stat.standardOptions.withUnit('percentunit')
    + g.panel.stat.standardOptions.thresholds.withSteps([
        { color: 'green', value: null },
        { color: 'yellow', value: 0.01 },
        { color: 'red', value: 0.05 },
      ]),
}
